#include <iostream>
#include <string>
using namespace std;

class Book {
public:
    string title;
    string author;
    int year;

    // 1. Конструктор ЗА ЗАМОВЧУВАННЯМ (Без параметрів)
    // Якщо користувач створить просто Book b1;
    Book() : title("Без назви"), author("Невідомий"), year(0) {
        cout << "[Збірка] Створена пуста книга" << endl;
    }

    // 2. Конструктор З ПАРАМЕТРАМИ
    // Спеціальний швидкий список ініціалізації:
    Book(string t, string a, int y) : title(t), author(a), year(y) {
        cout << "[Збірка] Книгу '" << title << "' надруковано!" << endl;
    }

    // 3. Конструктор копіювання (якщо просто копіюємо іншу книгу)
    Book(const Book& otherBase) {
        title = otherBase.title + " (Копія)";
        author = otherBase.author;
        year = otherBase.year;
    }

    // 4. ДЕСТРУКТОР. Знищує книгу після закінчення програми (чи блоку {})
    ~Book() {
        cout << "[Смітник] Книга '" << title << "' згоріла..." << endl;
    }

    void show() {
        cout << " -> " << title << " | Автор: " << author 
             << " | Випущено: " << year << endl;
    }
};

int main() {
    cout << "=== Початок Бібліотеки ===" << endl;

    Book b1; // Викличе перший конструктор
    b1.show();

    Book b2("Кобзар", "Тарас Шевченко", 1840); // Викличе другий!
    b2.show();

    Book b3 = b2; // Викличе третій (копіювання)
    b3.show();

    cout << "=== Закриваємо програму ===" << endl;
    // Відразу після return всі змінні зі стеку будуть знищені НАВПАКИ! 
    // b3 згорить, потім b2, потім b1 (принцип LIFO). 
    return 0;
}
